// @vitest-environment node
/**
 * SPEC-020: Capturas — generación de guión sin empresa (degradación del
 * prompt) y regeneración completa tras asignar empresa.
 * Generated by QA Dev agent.
 *
 * Mismo arnés que llmService.test.ts (SPEC-014): SDK de Anthropic mockeado con
 * clases de error espejo y store/repository REALES en directorio temporal.
 */
import { mkdtempSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import { generateInterviewScript, LlmOperationError } from '../../../src/main/llmService'
import * as repository from '../../../src/main/db/repository'
import { initStore } from '../../../src/main/db/store'
import type {
  Discovery,
  Interview,
  InterviewTemplate
} from '../../../src/renderer/src/types/domain'

const harness = vi.hoisted(() => {
  /** Jerarquía espejo de la del SDK: instanceof debe funcionar en mapSdkError. */
  class APIError extends Error {}
  class AuthenticationError extends APIError {}
  class RateLimitError extends APIError {}
  class APIConnectionError extends APIError {}
  return {
    create: vi.fn(),
    errors: { APIError, AuthenticationError, RateLimitError, APIConnectionError }
  }
})

vi.mock('@anthropic-ai/sdk', () => {
  class MockAnthropic {
    static APIError = harness.errors.APIError
    static AuthenticationError = harness.errors.AuthenticationError
    static RateLimitError = harness.errors.RateLimitError
    static APIConnectionError = harness.errors.APIConnectionError
    readonly messages = { create: harness.create }
  }
  return { default: MockAnthropic }
})

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  },
  safeStorage: {
    isEncryptionAvailable: (): boolean => true,
    encryptString: (plain: string): Buffer => Buffer.from(plain, 'utf8'),
    decryptString: (blob: Buffer): string => blob.toString('utf8')
  }
}))

/** Respuesta del SDK con bloque thinking + bloque text (el JSON va en text). */
function sdkResponse(text: string): unknown {
  return {
    stop_reason: 'end_turn',
    content: [
      { type: 'thinking', thinking: 'razonamiento interno' },
      { type: 'text', text }
    ]
  }
}

const VALID_JSON = JSON.stringify({
  scriptMarkdown: '# Guión adaptado a la captura',
  objectives: ['Objetivo uno', 'Objetivo dos', 'Objetivo tres']
})

interface SeededCapture {
  capture: Interview
  discovery: Discovery
  template: InterviewTemplate
}

/** Discovery + template + CAPTURA sin empresa (capture-first). */
function seedCapture(options: { withTemplate?: boolean } = {}): SeededCapture {
  const { withTemplate = true } = options
  const discovery = repository.createDiscovery({ name: 'Vertical Sanidad' })
  const template = repository.createInterviewTemplate({
    name: 'Entrevista de problema',
    phase: 'problem',
    blocks: [{ title: 'Contexto', questions: [{ text: '¿Quién lleva el regulatorio?' }] }]
  })
  const capture = repository.createInterview({
    discoveryId: discovery.id,
    title: 'Captura sin empresa',
    templateId: withTemplate ? template.id : null
  })
  return { capture, discovery, template }
}

function sentUserPrompt(): string {
  const params = harness.create.mock.calls[0][0] as {
    messages: Array<{ role: string; content: string }>
  }
  return params.messages[0].content
}

function sentSystemPrompt(): string {
  const params = harness.create.mock.calls[0][0] as { system: string }
  return params.system
}

let dataDir = ''

beforeEach(() => {
  vi.clearAllMocks()
  dataDir = mkdtempSync(join(tmpdir(), 'maurya-llm-captures-'))
  initStore(dataDir)
  process.env['ANTHROPIC_API_KEY'] = 'sk-ant-test-key'
})

afterEach(() => {
  delete process.env['ANTHROPIC_API_KEY']
})

describe('llmService (SPEC-020 capturas)', () => {
  describe('generation without a company', () => {
    // SPEC-020 · AC-18
    it('generates from the template and the discovery name only, omitting the company/contact/history sections, and sets status prepared', async () => {
      const { capture } = seedCapture()
      harness.create.mockResolvedValue(sdkResponse(VALID_JSON))

      const updated = await generateInterviewScript(capture.id)

      // El discovery viaja como único contexto...
      const userPrompt = sentUserPrompt()
      expect(userPrompt).toContain('## Discovery\nNombre: Vertical Sanidad')
      expect(userPrompt).toContain('## Template de entrevista')
      // ...y las secciones de empresa/contacto/histórico se omiten
      expect(userPrompt).not.toContain('## Empresa')
      expect(userPrompt).not.toContain('## Contacto')
      expect(userPrompt).not.toContain('## Entrevistas anteriores')
      // El system prompt ancla la adaptación al contexto del discovery
      expect(sentSystemPrompt()).toContain('al contexto del discovery')
      expect(sentSystemPrompt()).not.toContain('a la empresa y al contacto concretos')
      // Y la captura queda preparada con el guión persistido
      expect(updated.status).toBe('prepared')
      expect(repository.getInterview(capture.id).scriptMarkdown).toBe(
        '# Guión adaptado a la captura'
      )
    })

    // SPEC-020 · AC-19
    it('fails with the no-template block without calling the LLM when the capture has no template', async () => {
      const { capture } = seedCapture({ withTemplate: false })

      const caught = await generateInterviewScript(capture.id).then(
        () => null,
        (error: unknown) => error
      )

      expect(caught).toBeInstanceOf(LlmOperationError)
      expect((caught as LlmOperationError).kind).toBe('no-template')
      expect(harness.create).not.toHaveBeenCalled()
      expect(repository.getInterview(capture.id).status).toBe('draft')
    })
  })

  describe('regeneration after assigning a company', () => {
    // SPEC-020 · AC-20
    it('includes the company, the contact and the company historical context again when regenerating after assignment', async () => {
      const { capture, discovery } = seedCapture()
      // Se asigna una empresa nueva con contacto nuevo (operación compuesta real)
      const assigned = repository.assignInterviewCompany(capture.id, {
        newCompany: { name: 'Acme Corp', website: 'https://acme.example' },
        newContact: { name: 'Jane Doe', position: 'CTO' }
      })
      // Entrevista previa de ESA empresa con nota: vuelve el contexto histórico
      const previous = repository.createInterview({
        discoveryId: discovery.id,
        companyId: assigned.company.id,
        title: 'Primera toma de contacto'
      })
      repository.createNote({
        interviewId: previous.id,
        contentMarkdown: 'El CTO gestiona el regulatorio con hojas de cálculo'
      })
      harness.create.mockResolvedValue(sdkResponse(VALID_JSON))

      await generateInterviewScript(capture.id)

      const userPrompt = sentUserPrompt()
      // La generación vuelve al camino completo: empresa + contacto + histórico
      expect(userPrompt).toContain('## Empresa\nNombre: Acme Corp')
      expect(userPrompt).toContain('Web: https://acme.example')
      expect(userPrompt).toContain('## Contacto\nNombre: Jane Doe')
      expect(userPrompt).toContain('## Entrevistas anteriores')
      expect(userPrompt).toContain('El CTO gestiona el regulatorio con hojas de cálculo')
      // El discovery sigue presente también con empresa (sección nueva de SPEC-020)
      expect(userPrompt).toContain('## Discovery\nNombre: Vertical Sanidad')
      expect(sentSystemPrompt()).toContain('a la empresa y al contacto concretos')
    })
  })
})
